// Arduino가 기대하는 형식: "pump=1 fan=128"
// switch/slider가 각각 들어올 수 있어 마지막 값을 context에 저장해서 합칩니다.

const devId = flow.get('deviceId') || 'cronusfarm-01';
flow.set('deviceId', devId);

const pump = (msg._ui && msg._ui.type === 'switch') ? msg.payload : flow.get('pump');
const fan  = (msg._ui && msg._ui.type === 'slider') ? msg.payload : flow.get('fan');

if (msg._ui && msg._ui.type === 'switch') flow.set('pump', pump);
if (msg._ui && msg._ui.type === 'slider') flow.set('fan', fan);

const p = (pump === undefined) ? (flow.get('pump') ?? '0') : pump;
const f = (fan === undefined)  ? (flow.get('fan')  ?? '0') : fan;

msg.topic = `cronusfarm/${devId}/cmd`;
msg.payload = `pump=${p} fan=${f}`;
return msg;

msg.payload = (msg.payload || '').toString().trim();
if (!msg.payload) return null;
return msg;

// MQTT tele → InfluxDB 2.x Line Protocol (측정값만, 토큰은 환경변수)
// 필요: CRONUSFARM_INFLUX_TOKEN, 선택: CRONUSFARM_INFLUX_ORG, CRONUSFARM_INFLUX_BUCKET, CRONUSFARM_INFLUX_MIN_MS
// 주의: Function 노드에서는 process.env 가 없으므로 env.get(...)를 사용합니다.

const token = (env.get('CRONUSFARM_INFLUX_TOKEN') || '').toString().trim();
if (!token) {
  if (!flow.get('_influxWarned')) {
    flow.set('_influxWarned', true);
    node.warn('Influx: CRONUSFARM_INFLUX_TOKEN 없음 → 기록 생략');
  }
  return null;
}

const minMs = parseInt((env.get('CRONUSFARM_INFLUX_MIN_MS') || '5000').toString(), 10) || 5000;
const now = Date.now();
const last = flow.get('lastInfluxWriteMs') || 0;
if (now - last < minMs) return null;
flow.set('lastInfluxWriteMs', now);

const s = (msg.payload || '').toString();
function parseKV(part) {
  const out = {};
  (part || '').trim().split(/\s+/).forEach(tok => {
    const m = tok.match(/^([^=]+)=(.+)$/);
    if (!m) return;
    out[m[1]] = m[2];
  });
  return out;
}

const ps = s.split('|').map(x => x.trim());
const pS = ps.find(x => x.startsWith('S:'));
const pA = ps.find(x => x.startsWith('A:'));
const pT = ps.find(x => x.startsWith('T:'));
const kvS = parseKV(pS ? pS.slice(2) : '');
const kvA = parseKV(pA ? pA.slice(2) : '');
const kvT = parseKV(pT ? pT.slice(2) : '');

const parts = (msg.topic || '').toString().split('/').filter(Boolean);
const deviceId = (parts.length >= 2 ? parts[1] : 'cronusfarm-01').replace(/[^a-zA-Z0-9_-]/g, '_');

const fields = [];
const ch = ['led_a1', 'led_a2', 'pump_a1', 'pump_a2', 'led_b1', 'pump_b1', 'pump_b2'];
ch.forEach(k => {
  if (kvS[k] === undefined) return;
  fields.push(`${k}=${kvS[k] === '1' ? 1 : 0}i`);
});
ch.forEach(k => {
  if (kvA[k] === undefined) return;
  fields.push(`auto_${k}=${kvA[k] === '1' ? 1 : 0}i`);
});
Object.keys(kvT).forEach(k => {
  const m = (kvT[k] || '').toString().match(/^(\d+)\/(\d+)$/);
  if (!m) return;
  fields.push(`${k}_on_s=${parseInt(m[1], 10)}i`);
  fields.push(`${k}_off_s=${parseInt(m[2], 10)}i`);
});

if (!fields.length) return null;

const org = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_ORG') || 'cronusfarm').toString()));
const bucket = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_BUCKET') || 'cronusfarm').toString()));
const base = ((env.get('CRONUSFARM_INFLUX_URL') || 'http://127.0.0.1:8086/api/v2/write').toString()).replace(/\/$/, '');

msg.method = 'POST';
msg.url = `${base}?org=${org}&bucket=${bucket}&precision=ns`;
msg.headers = {
  Authorization: `Token ${token}`,
  'Content-Type': 'text/plain; charset=utf-8'
};
msg.payload = `tele,device_id=${deviceId} ${fields.join(',')} ${now * 1e6}`;
return msg;

// 알림/이벤트(JSON) → InfluxDB (measurement: alert_events)
// bucket은 환경변수 CRONUSFARM_INFLUX_BUCKET(권장: CronusFarm)을 사용합니다.

const token = (env.get('CRONUSFARM_INFLUX_TOKEN') || '').toString().trim();
if (!token) return null;

const p = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};

function escTag(v) {
  return (v ?? '').toString().replace(/[,=\s]/g, '_');
}
function escStr(v) {
  return (v ?? '').toString().replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}
function numOrNull(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

const now = Date.now();
const org = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_ORG') || 'cronusfarm').toString()));
const bucket = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_BUCKET') || 'CronusFarm').toString()));
const base = ((env.get('CRONUSFARM_INFLUX_URL') || 'http://127.0.0.1:8086/api/v2/write').toString()).replace(/\/$/, '');

const tags = [`source=${escTag(p.source || 'unknown')}`];
if (p.zone) tags.push(`zone=${escTag(p.zone)}`);
if (p.alert_type) tags.push(`alert_type=${escTag(p.alert_type)}`);

const fields = [];
if (p.severity !== undefined) fields.push(`severity=\"${escStr(p.severity)}\"`);
if (p.message !== undefined) fields.push(`message=\"${escStr(p.message)}\"`);

const va = numOrNull(p.value_actual);
if (va !== null) fields.push(`value_actual=${va}`);
const vt = numOrNull(p.value_threshold);
if (vt !== null) fields.push(`value_threshold=${vt}`);

if (!fields.length) return null;

msg.method = 'POST';
msg.url = `${base}?org=${org}&bucket=${bucket}&precision=ns`;
msg.headers = { Authorization: `Token ${token}`, 'Content-Type': 'text/plain; charset=utf-8' };
msg.payload = `alert_events,${tags.join(',')} ${fields.join(',')} ${now * 1e6}`;
return msg;

// AI 감지(JSON) → InfluxDB (measurement: ai_detections)

const token = (env.get('CRONUSFARM_INFLUX_TOKEN') || '').toString().trim();
if (!token) return null;

const p = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};

function escTag(v) {
  return (v ?? '').toString().replace(/[,=\s]/g, '_');
}
function escStr(v) {
  return (v ?? '').toString().replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}
function numOrNull(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

const now = Date.now();
const org = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_ORG') || 'cronusfarm').toString()));
const bucket = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_BUCKET') || 'CronusFarm').toString()));
const base = ((env.get('CRONUSFARM_INFLUX_URL') || 'http://127.0.0.1:8086/api/v2/write').toString()).replace(/\/$/, '');

const tags = [];
if (p.zone) tags.push(`zone=${escTag(p.zone)}`);
if (p.camera) tags.push(`camera=${escTag(p.camera)}`);
if (p.detection_type) tags.push(`detection_type=${escTag(p.detection_type)}`);
if (p.label) tags.push(`label=${escTag(p.label)}`);

const fields = [];
const conf = numOrNull(p.confidence);
if (conf !== null) fields.push(`confidence=${conf}`);
if (p.severity !== undefined) fields.push(`severity=\"${escStr(p.severity)}\"`);
if (p.model_name !== undefined) fields.push(`model_name=\"${escStr(p.model_name)}\"`);
if (p.model_version !== undefined) fields.push(`model_version=\"${escStr(p.model_version)}\"`);
if (p.is_confirmed !== undefined) fields.push(`is_confirmed=${(p.is_confirmed ? 1 : 0)}i`);

if (!fields.length) return null;

msg.method = 'POST';
msg.url = `${base}?org=${org}&bucket=${bucket}&precision=ns`;
msg.headers = { Authorization: `Token ${token}`, 'Content-Type': 'text/plain; charset=utf-8' };
msg.payload = `ai_detections${tags.length ? ',' + tags.join(',') : ''} ${fields.join(',')} ${now * 1e6}`;
return msg;

// 기상청 초단기실황(getUltraSrtNcst) → JSON
// env:
// - CRONUSFARM_KMA_SERVICE_KEY : 디코딩된 서비스키(= 포함 원문) 권장
// - CRONUSFARM_KMA_NX / CRONUSFARM_KMA_NY : 격자 좌표
// 주의: KMA는 KST(UTC+9) 기준 base_date/base_time을 사용합니다.

const key = (env.get('CRONUSFARM_KMA_SERVICE_KEY') || '').toString().trim();
const nx = parseInt((env.get('CRONUSFARM_KMA_NX') || '0').toString(), 10) || 0;
const ny = parseInt((env.get('CRONUSFARM_KMA_NY') || '0').toString(), 10) || 0;
if (!key || !nx || !ny) {
  node.warn('KMA: SERVICE_KEY 또는 NX/NY 누락 → 수집 생략');
  return null;
}

function pad2(n) { return (n < 10 ? '0' : '') + n; }

// KST now
const nowUtc = new Date();
const nowKstMs = nowUtc.getTime() + (9 * 60 * 60 * 1000);
const nowKst = new Date(nowKstMs);

let y = nowKst.getUTCFullYear();
let mo = nowKst.getUTCMonth() + 1;
let d = nowKst.getUTCDate();
let hh = nowKst.getUTCHours();
let mm = nowKst.getUTCMinutes();

// 발표 시각 여유: 매 시각 40분 이후에 해당 시간 데이터가 안정적으로 조회되는 경우가 많아
// 40분 이전이면 이전 시간(정시)로 물립니다.
if (mm < 40) {
  hh -= 1;
  if (hh < 0) {
    hh = 23;
    const prev = new Date(nowKstMs - 24 * 60 * 60 * 1000);
    y = prev.getUTCFullYear();
    mo = prev.getUTCMonth() + 1;
    d = prev.getUTCDate();
  }
}

const base_date = `${y}${pad2(mo)}${pad2(d)}`;
const base_time = `${pad2(hh)}00`;

const qs = new URLSearchParams({
  serviceKey: key,
  numOfRows: '60',
  pageNo: '1',
  dataType: 'JSON',
  base_date,
  base_time,
  nx: String(nx),
  ny: String(ny)
});

msg.method = 'GET';
msg.url = `https://apis.data.go.kr/1360000/VilageFcstInfoService_2.0/getUltraSrtNcst?${qs.toString()}`;
msg.headers = { 'User-Agent': 'CronusFarm/NodeRED' };
msg.kma = { base_date, base_time, nx, ny };
return msg;

// KMA 응답(JSON) → Influx write + MQTT 스냅샷(/ui Farm 환경)
// 출력1: Influx(토큰 있을 때만) · 출력2: cronusfarm/kma/snapshot(retain)

const token = (env.get('CRONUSFARM_INFLUX_TOKEN') || '').toString().trim();

function numOrNull(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

if (typeof msg.payload === 'string') {
  const raw = msg.payload;
  try {
    msg.payload = JSON.parse(raw);
  } catch (e) {
    node.warn('KMA: JSON 파싱 실패(응답 일부): ' + raw.slice(0, 200));
    return null;
  }
}

const body = msg.payload;
const items = body?.response?.body?.items?.item;
if (!Array.isArray(items)) {
  node.warn('KMA: items 없음/형식 불일치');
  return null;
}

const m = {};
for (const it of items) {
  const cat = (it?.category || '').toString();
  const val = (it?.obsrValue ?? '').toString();
  if (!cat) continue;
  m[cat] = val;
}

const temp = numOrNull(m.T1H);
const reh = numOrNull(m.REH);
const vec = numOrNull(m.VEC);
const wsd = numOrNull(m.WSD);
const pty = numOrNull(m.PTY);

const fields = [];
if (temp !== null) fields.push(`kma_temp=${temp}`);
if (reh !== null) fields.push(`kma_humidity=${reh}`);
if (vec !== null) fields.push(`kma_wind_dir=${vec}`);
if (wsd !== null) fields.push(`kma_wind_speed=${wsd}`);
if (pty !== null) fields.push(`kma_pty=${pty}i`);

const now = Date.now();
const org = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_ORG') || 'cronusfarm').toString()));
const bucket = encodeURIComponent(((env.get('CRONUSFARM_INFLUX_BUCKET') || 'CronusFarm').toString()));
const base = ((env.get('CRONUSFARM_INFLUX_URL') || 'http://127.0.0.1:8086/api/v2/write').toString()).replace(/\/$/, '');
const nx = msg.kma?.nx;
const ny = msg.kma?.ny;
const tags = [`source=kma`];
if (nx && ny) tags.push(`nx=${nx}`, `ny=${ny}`);

const snap = {
  kma_temp: temp,
  kma_humidity: reh,
  kma_wind_dir: vec,
  kma_wind_speed: wsd,
  kma_pty: pty,
  base_date: msg.kma?.base_date,
  base_time: msg.kma?.base_time,
  nx,
  ny,
  ts: now
};

const uiMsg = {
  topic: 'cronusfarm/kma/snapshot',
  qos: 0,
  retain: true,
  payload: JSON.stringify(snap)
};

let influxMsg = null;
if (token && fields.length) {
  influxMsg = {
    method: 'POST',
    url: `${base}?org=${org}&bucket=${bucket}&precision=ns`,
    headers: { Authorization: `Token ${token}`, 'Content-Type': 'text/plain; charset=utf-8' },
    payload: `tele,${tags.join(',')} ${fields.join(',')} ${now * 1e6}`
  };
}

return [ influxMsg, uiMsg ];
